import React from 'react';
import NavBar from "./Components/NavBar";
import {Grid, Paper} from "@material-ui/core";
import Image from "./Components/profile_pic.jpg";
import MediaCard from "./Components/Profile";
const styles = {
  gridContainer: {
    backgroundImage: `url(${Image})`,
    margin: 20,
  }
};
function App() {
  return (
    <React.Fragment>
    <NavBar />
  <Grid container style={styles.gridContainer}>
    <Grid item sm >
      <Paper >
        <MediaCard />
      </Paper>
    </Grid>
    <Grid item sm>
      <h1> How are you?</h1>
    </Grid>
  </Grid>
    </React.Fragment>
  );
}

export default App;
